    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    1,
    'Chair Yoga - 1w 4x/wk',
    'yoga',
    4,
    60,
    ARRAY['Improve flexibility', 'Enhance body awareness']::text[],
